            }

            for (i in 0 until n - gap) {
                if (result[i] > result[i + gap]) {
                    val temp = result[i]
                    result[i] = result[i + gap]
                    result[i + gap] = temp
                    sorted = false
                }
            }
        }

        return result
    }
