pub fn comb_sort(arr: &[i32]) -> Vec<i32> {
    let mut result = arr.to_vec();
    let n = result.len();
    let mut gap = n;
    let shrink = 1.3;
    let mut sorted = false;

    while !sorted {
        gap = (gap as f64 / shrink).floor() as usize;
        if gap <= 1 {
            gap = 1;
            sorted = true;
        }

        for i in 0..n - gap {
            if result[i] > result[i + gap] {
                result.swap(i, i + gap);
                sorted = false;
            }
        }
    }

    result
}

